export class ReviewsSystem{constructor(){this.storageKey="fnb_cafe_reviews",this.reviews=this.loadReviews(),this.init()}init(){this.renderReviews(),this.initStarRating(),this.initReviewForm(),this.initSorting(),this.updateAverageRating()}loadReviews(){const e=localStorage.getItem(this.storageKey);return e?JSON.parse(e):[{id:1,name:"Nguyễn Văn A",rating:5,comment:"Cà phê ngon, không gian đẹp! Nhân viên phục vụ nhiệt tình.",date:"2026-03-10",helpful:12},{id:2,name:"Trần Thị B",rating:4,comment:"Không gian check-in rất sống ảo. Đồ uống ổn, giá hợp lý.",date:"2026-03-12",helpful:8},{id:3,name:"Lê Văn C",rating:5,comment:"Container Special ngon tuyệt! Sẽ quay lại.",date:"2026-03-13",helpful:15}]}saveReviews(){localStorage.setItem(this.storageKey,JSON.stringify(this.reviews))}addReview(e){const t={id:Date.now(),name:e.name,rating:e.rating,comment:e.comment,date:(new Date).toISOString().split("T")[0],helpful:0};this.reviews.unshift(t),this.saveReviews(),this.renderReviews(),this.updateAverageRating()}initStarRating(){document.querySelectorAll(".star-rating-input").forEach(e=>{const t=e.parentElement.querySelectorAll(".star");t.forEach((n,i)=>{n.addEventListener("click",()=>{const n=i+1;e.value=n,this.updateStarDisplay(t,n)}),n.addEventListener("mouseenter",()=>{this.updateStarDisplay(t,i+1,!0)})}),e.parentElement.addEventListener("mouseleave",()=>{const n=parseInt(e.value)||0;this.updateStarDisplay(t,n)})})}updateStarDisplay(e,t,n=!1){const i=n?"star-fill-hover":"star-fill";e.forEach((e,n)=>{n<t?(e.classList.add(i),e.classList.remove("star-empty")):(e.classList.remove(i),e.classList.add("star-empty"))})}initReviewForm(){const e=document.getElementById("reviewForm");e&&e.addEventListener("submit",t=>{t.preventDefault();const n=document.getElementById("reviewerName")?.value.trim(),i=document.getElementById("reviewRating")?.value,s=document.getElementById("reviewComment")?.value.trim();if(!n||!i||!s)return void this.showNotification("Vui lòng điền đầy đủ thông tin!","error");if(i<1)return void this.showNotification("Vui lòng chọn số sao!","error");this.addReview({name:n,rating:i,comment:s}),e.reset(),document.querySelectorAll(".star-rating-input").forEach(e=>{e.value=0,this.updateStarDisplay(e.parentElement.querySelectorAll(".star"),0)}),this.showNotification("Cảm ơn bạn đã đánh giá!","success");const a=document.getElementById("reviewModal");a&&a.classList.remove("active")})}renderReviews(e="newest"){const t=document.getElementById("reviewsList");if(!t)return;let n=[...this.reviews];switch(e){case"highest":n.sort((e,t)=>t.rating-e.rating);break;case"lowest":n.sort((e,t)=>e.rating-t.rating);break;case"helpful":n.sort((e,t)=>t.helpful-e.helpful);break;default:n.sort((e,t)=>new Date(t.date)-new Date(e.date))}t.innerHTML=n.map(e=>this.renderReviewCard(e)).join(""),t.querySelectorAll(".helpful-btn").forEach(e=>{e.addEventListener("click",e=>{const t=parseInt(e.target.dataset.reviewId);this.markHelpful(t)})})}renderReviewCard(e){const t=this.renderStars(e.rating,!1),n=new Date(e.date).toLocaleDateString("vi-VN",{year:"numeric",month:"long",day:"numeric"});return`\n            <div class="review-card reveal" data-rating="${e.rating}">\n                <div class="review-header">\n                    <div class="reviewer-info">\n                        <div class="reviewer-avatar">\n                            ${e.name.charAt(0).toUpperCase()}\n                        </div>\n                        <div class="reviewer-details">\n                            <h4 class="reviewer-name">${this.escapeHtml(e.name)}</h4>\n                            <span class="review-date">${n}</span>\n                        </div>\n                    </div>\n                    <div class="review-rating">\n                        ${t}\n                    </div>\n                </div>\n                <p class="review-comment">${this.escapeHtml(e.comment)}</p>\n                <div class="review-footer">\n                    <button class="helpful-btn" data-review-id="${e.id}">\n                        👍 Hữu ích (${e.helpful})\n                    </button>\n                </div>\n            </div>\n        `}renderStars(e,t=!0){const n=t?`<input type="hidden" class="star-rating-input" value="${e}">`:"";let i="";for(let t=1;t<=5;t++){i+=`<span class="star ${t<=e?"star-fill":"star-empty"}">★</span>`}return`<div class="star-rating ${t?"interactive":""}">\n            ${n}${i}\n        </div>`}initSorting(){const e=document.getElementById("reviewSort");e&&e.addEventListener("change",e=>{this.renderReviews(e.target.value)})}updateAverageRating(){const e=this.reviews.length,t=this.reviews.reduce((e,t)=>e+t.rating,0),n=e>0?(t/e).toFixed(1):0,i=document.getElementById("averageRating");i&&(i.textContent=n);const s=document.getElementById("totalReviews");s&&(s.textContent=e),this.renderRatingDistribution()}renderRatingDistribution(){const e=document.getElementById("ratingDistribution");if(!e)return;const t=[5,4,3,2,1].map(e=>{const t=this.reviews.filter(t=>t.rating===e).length,n=this.reviews.length>0?(t/this.reviews.length*100).toFixed(0):0;return{stars:e,count:t,percentage:n}});e.innerHTML=t.map(e=>`\n            <div class="rating-bar">\n                <span class="rating-bar-stars">${e.stars} ★</span>\n                <div class="rating-bar-track">\n                    <div class="rating-bar-fill" style="width: ${e.percentage}%"></div>\n                </div>\n                <span class="rating-bar-count">${e.count}</span>\n            </div>\n        `).join("")}markHelpful(e){const t=this.reviews.find(t=>t.id===e);t&&(t.helpful++,this.saveReviews(),this.renderReviews())}escapeHtml(e){const t=document.createElement("div");return t.textContent=e,t.innerHTML}showNotification(e,t="success"){const n=document.querySelector(".review-notification");n&&n.remove();const i=document.createElement("div");i.className=`review-notification ${t}`,i.textContent=e,document.body.appendChild(i),setTimeout(()=>{i.classList.add("show")},10),setTimeout(()=>{i.classList.remove("show"),setTimeout(()=>i.remove(),300)},3e3)}filterByRating(e){const t=document.getElementById("reviewsList");if(!t)return;t.querySelectorAll(".review-card").forEach(t=>{const n=parseInt(t.dataset.rating);t.style.display=n>=e||0===e?"block":"none"})}}"undefined"!=typeof window&&document.addEventListener("DOMContentLoaded",()=>{window.reviewsSystem=new ReviewsSystem});